from typing import List

class Solution:
    def sumIndicesWithKSetBits(self, nums: List[int], k: int) -> int:
        def popcount(x: int) -> int:
            return x.bit_count()

        total = 0
        for i, val in enumerate(nums):
            if popcount(i) == k:
                total += val
        return total
```

